script.res:
const data = res.getBody();

const token = data.access_token;
bru.setEnvVar("TOKEN", token);
console.info("Set TOKEN env var.");

const decodeJwtPart = (value) => {
  return JSON.parse(Buffer.from(value, "base64url").toString("utf8"));
};

try {
  const parts = token.split(".");
  if (parts.length < 2) {
    throw new Error("Returned token is not a valid JWT.");
  }

  const header = decodeJwtPart(parts[0]);
  const payload = decodeJwtPart(parts[1]);

  console.info("Decoded header.typ:", header.typ);
  console.info("Decoded payload.iss:", payload.iss);
  console.info("Decoded payload.exp (token expiry):", new Date(payload.exp * 1000).toISOString());
} catch (error) {
  console.error("Failed to decode access_token:", error.message || error);
}

const body = res.getBody();
const resources = Array.isArray(body?.resources) ? body.resources : [];

const str = (v) => {
  if (v == null) return "";
  if (typeof v === "object") return JSON.stringify(v);
  return String(v);
};

const rows = resources.map((s) => {
  const row = {};
  for (const [k, v] of Object.entries(s)) row[k] = str(v);
  return row;
});

const columnDefinitions = Array.from(
  new Set(rows.flatMap((r) => Object.keys(r)))
).map((k) => ({ field: k, filter: true, floatingFilter: true }));

bru.visualize("table", {
  name: "Table View",
  provider: "ag-grid",
  props: { rowData: rows, columnDefinitions },
});

const body = res.getBody();
const resources = Array.isArray(body?.resources) ? body.resources : [];

const str = (v) => {
  if (v == null) return "";
  if (typeof v === "object") return JSON.stringify(v);
  return String(v);
};

const rows = [];
const columnKeys = new Set();

const addField = (row, key, value) => {
  row[key] = str(value);
  columnKeys.add(key);
};

const MODEL_PINNED = ["displayName", "model"];
const MODEL_PINNED_SET = new Set(MODEL_PINNED);

for (const model of resources) {
  const modelEntries = Object.entries(model);
  const versions = Array.isArray(model.versions) ? model.versions : [];

  for (const version of versions) {
    const row = {};

    for (const k of MODEL_PINNED) addField(row, k, model[k]);

    addField(row, "version", version.name);
    for (const [k, v] of Object.entries(version)) {
      if (k === "name") continue;
      addField(row, k, v);
    }

    for (const [k, v] of modelEntries) {
      if (k === "versions" || MODEL_PINNED_SET.has(k)) continue;
      addField(row, k, v);
    }

    rows.push(row);
  }
}

const columnDefinitions = Array.from(columnKeys).map((k) => ({
  field: k,
  filter: true,
  floatingFilter: true,
}));

bru.visualize("table", {
  name: "Table View",
  provider: "ag-grid",
  props: { rowData: rows, columnDefinitions },
});

