script.res:
const data = res.getBody();
if (data?.id) {
  bru.setEnvVar("MODEL_DEPLOYMENT_ID", data.id);
  console.info("Set MODEL_DEPLOYMENT_ID:", data.id, "| Status:", data.status);
  console.info("The deployment starts as PENDING and transitions to RUNNING.");
  console.info("Run '6 - List Deployments' after a few minutes to get the deployment URL once it is RUNNING.");
} else {
  console.error("Unexpected response:", JSON.stringify(data));
}

const data = res.getBody();
const resources = Array.isArray(data?.resources) ? data.resources : [];

const target = resources[0];

if (target) {
  bru.setEnvVar("MODEL_DEPLOYMENT_ID", target.id);
  bru.setEnvVar("MODEL_DEPLOYMENT_URL", target.deploymentUrl || "");
  console.info(
    "Set MODEL_DEPLOYMENT_ID:", target.id,
    "| MODEL_DEPLOYMENT_URL:", target.deploymentUrl || "(not yet available)",
    "| Status:", target.status,
    "| model config:", target.configurationName
  );
} else {
  console.info("No deployments found.");
}

// Table view of all deployments
const rows = resources.map(r => ({
  id: r.id || "",
  configurationName: r.configurationName || "",
  status: r.status || "",
  deploymentUrl: r.deploymentUrl || "",
  createdAt: r.createdAt || "",
  modifiedAt: r.modifiedAt || "",
}));

const columnDefinitions = Object.keys(rows[0] || {}).map(k => ({
  field: k,
  filter: true,
  floatingFilter: true,
}));

bru.visualize("table", {
  name: "Deployments",
  provider: "ag-grid",
  props: { rowData: rows, columnDefinitions },
});

const data = res.getBody();
if (data?.id) {
  console.info("Stop initiated. ID:", data.id, "| targetStatus:", data.targetStatus, "| current status:", data.status);
  console.info("Wait for status to become STOPPED, then run '8 - Delete Deployment'.");
} else {
  console.error("Unexpected response:", JSON.stringify(data));
}

const data = res.getBody();
if (res.status === 202 || data?.id) {
  console.info("Deployment deletion initiated. ID:", data?.id, "| Status:", data?.targetStatus ?? data?.status);
  console.info("The deployment will transition to STOPPED then be removed.");
  bru.setEnvVar("MODEL_DEPLOYMENT_URL", "");
  bru.setEnvVar("MODEL_DEPLOYMENT_ID", "");
  console.info("Cleared MODEL_DEPLOYMENT_URL and MODEL_DEPLOYMENT_ID.");
} else {
  console.error("Unexpected response:", JSON.stringify(data));
}

